In that case, you can achieve one index cache per index file by creating a cache instance for each index file. Here's a high-level example of how you can implement this:

```python
import os
import pickle

class IndexCache:
    def __init__(self, index_file):
        self.index_file = index_file
        self.cache = {}

    def get(self, key):
        if key in self.cache:
            return self.cache[key]
        else:
            # Load the index file and update the cache
            with open(self.index_file, 'rb') as f:
                index_data = pickle.load(f)
            self.cache = index_data
            return self.cache.get(key)

    def set(self, key, value):
        self.cache[key] = value
        # Save the updated cache to the index file
        with open(self.index_file, 'wb') as f:
            pickle.dump(self.cache, f)

    def delete(self, key):
        if key in self.cache:
            del self.cache[key]
            # Save the updated cache to the index file
            with open(self.index_file, 'wb') as f:
                pickle.dump(self.cache, f)

