// @/src/hooks/useNotification.ts
import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from 'huel-notification';

export const NotificationContext = createContext<HTMLHuelNotificationElement | null>(null);

export const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (notificationElem) {
      return () => {
        notificationElem.close();
      };
    }
  }, [notificationElem]);

  const notify = async (props: Parameters<NotificationContext['open']>[0]) => {
    if (!notificationElem) return;

    try {
      await notificationElem.open(props);
    } catch (error) {
      setError(error);
    }
  };

  return { notify, error };
};
